<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #0d1117;
    color: #e6edf3;
    font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
    gap: 1.25rem;
    padding: 1.5rem;
  }
  h1 {
    font-size: 1.5rem;
    font-weight: 700;
    letter-spacing: 0.04em;
    background: linear-gradient(90deg, #58a6ff, #bc8cff, #f778ba);
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
  }
  .panel {
    display: flex;
    flex-wrap: wrap;
    gap: 0.6rem;
    justify-content: center;
    align-items: center;
  }
  button {
    appearance: none;
    border: 1px solid #30363d;
    background: #21262d;
    color: #e6edf3;
    font-size: 0.9rem;
    font-weight: 600;
    padding: 0.55rem 1.1rem;
    border-radius: 999px;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s, transform 0.1s, box-shadow 0.15s;
  }
  button:hover {
    background: #30363d;
    border-color: #58a6ff;
    box-shadow: 0 0 12px rgba(88, 166, 255, 0.25);
  }
  button:active { transform: scale(0.96); }
  button.playing {
    background: #238636;
    border-color: #2ea043;
    color: #fff;
  }
  button.playing:hover {
    background: #2ea043;
  }
  #life {
    width: 400px;
    height: 400px;
    background: #010409;
    border: 2px solid #30363d;
    border-radius: 8px;
    box-shadow: 0 0 40px rgba(88, 166, 255, 0.12), inset 0 0 60px rgba(0,0,0,0.5);
    cursor: crosshair;
    image-rendering: pixelated;
    touch-action: none;
  }
  .hint {
    font-size: 0.8rem;
    color: #8b949e;
  }
</style>
</head>
<body>
  <h1>✦ Conway's Game of Life ✦</h1>
  <canvas id="life" width="400" height="400"></canvas>
  <div class="panel">
    <button id="step" type="button">Step ▸</button>
    <button id="play" type="button">Play ▶</button>
    <button id="random" type="button">Random 🎲</button>
    <button id="clear" type="button">Clear ✕</button>
  </div>
  <p class="hint">Click &amp; drag to paint · B3/S23 · edges are dead</p>
<script>
(function () {
  const W = 40;
  const H = 40;
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const CSS_SIZE = 400;
  canvas.style.width = CSS_SIZE + 'px';
  canvas.style.height = CSS_SIZE + 'px';
  // HiDPI backing store
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  canvas.width = CSS_SIZE * dpr;
  canvas.height = CSS_SIZE * dpr;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  const cellW = CSS_SIZE / W;
  const cellH = CSS_SIZE / H;

  // Flat array: 0 dead, 1 alive
  let grid = new Uint8Array(W * H);

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    if (x < 0 || y < 0 || x >= W || y >= H) return 0;
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    grid[idx(x, y)] = v ? 1 : 0;
  }

  function countNeighbors(x, y) {
    let n = 0;
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        if (dx === 0 && dy === 0) continue;
        n += get(x + dx, y + dy);
      }
    }
    return n;
  }

  function step() {
    const next = new Uint8Array(W * H);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const alive = grid[idx(x, y)];
        const n = countNeighbors(x, y);
        // B3/S23
        if (alive) {
          next[idx(x, y)] = (n === 2 || n === 3) ? 1 : 0;
        } else {
          next[idx(x, y)] = (n === 3) ? 1 : 0;
        }
      }
    }
    grid = next;
    draw();
  }

  function clear() {
    grid.fill(0);
    draw();
  }

  function randomize() {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.28 ? 1 : 0;
    }
    draw();
  }

  function draw() {
    // background
    ctx.fillStyle = '#010409';
    ctx.fillRect(0, 0, CSS_SIZE, CSS_SIZE);

    // subtle grid lines
    ctx.strokeStyle = 'rgba(48, 54, 61, 0.45)';
    ctx.lineWidth = 0.5;
    ctx.beginPath();
    for (let x = 0; x <= W; x++) {
      ctx.moveTo(x * cellW + 0.25, 0);
      ctx.lineTo(x * cellW + 0.25, CSS_SIZE);
    }
    for (let y = 0; y <= H; y++) {
      ctx.moveTo(0, y * cellH + 0.25);
      ctx.lineTo(CSS_SIZE, y * cellH + 0.25);
    }
    ctx.stroke();

    // live cells
    const pad = 0.8;
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (!grid[idx(x, y)]) continue;
        const px = x * cellW;
        const py = y * cellH;
        // soft glow
        const g = ctx.createRadialGradient(
          px + cellW / 2, py + cellH / 2, 0,
          px + cellW / 2, py + cellH / 2, cellW * 0.7
        );
        g.addColorStop(0, '#79c0ff');
        g.addColorStop(0.55, '#58a6ff');
        g.addColorStop(1, 'rgba(88,166,255,0.15)');
        ctx.fillStyle = g;
        ctx.fillRect(px + pad, py + pad, cellW - pad * 2, cellH - pad * 2);
      }
    }
  }

  // Painting
  let painting = false;
  let paintValue = 1;

  function cellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = CSS_SIZE / rect.width;
    const scaleY = CSS_SIZE / rect.height;
    const cx = (e.clientX - rect.left) * scaleX;
    const cy = (e.clientY - rect.top) * scaleY;
    const x = Math.floor(cx / cellW);
    const y = Math.floor(cy / cellH);
    return { x, y };
  }

  function paintAt(e) {
    const { x, y } = cellFromEvent(e);
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    set(x, y, paintValue);
    draw();
  }

  canvas.addEventListener('mousedown', function (e) {
    if (e.button !== 0) return;
    painting = true;
    const { x, y } = cellFromEvent(e);
    // toggle: if currently alive, paint dead; else paint alive
    paintValue = get(x, y) ? 0 : 1;
    paintAt(e);
    e.preventDefault();
  });
  window.addEventListener('mouseup', function () { painting = false; });
  canvas.addEventListener('mousemove', function (e) {
    if (!painting) return;
    paintAt(e);
  });
  canvas.addEventListener('mouseleave', function () { /* keep painting if button held outside? stop */ });

  // Touch support
  canvas.addEventListener('touchstart', function (e) {
    if (e.touches.length !== 1) return;
    painting = true;
    const t = e.touches[0];
    const fake = { clientX: t.clientX, clientY: t.clientY };
    const { x, y } = cellFromEvent(fake);
    paintValue = get(x, y) ? 0 : 1;
    paintAt(fake);
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener('touchmove', function (e) {
    if (!painting || e.touches.length !== 1) return;
    const t = e.touches[0];
    paintAt({ clientX: t.clientX, clientY: t.clientY });
    e.preventDefault();
  }, { passive: false });
  canvas.addEventListener('touchend', function () { painting = false; });

  // Controls
  const stepBtn = document.getElementById('step');
  const playBtn = document.getElementById('play');
  const randomBtn = document.getElementById('random');
  const clearBtn = document.getElementById('clear');

  let playing = false;
  let timer = null;
  const INTERVAL = 120;

  function setPlaying(on) {
    playing = on;
    if (timer) { clearInterval(timer); timer = null; }
    if (playing) {
      timer = setInterval(step, INTERVAL);
      playBtn.textContent = 'Pause ⏸';
      playBtn.classList.add('playing');
    } else {
      playBtn.textContent = 'Play ▶';
      playBtn.classList.remove('playing');
    }
  }

  stepBtn.addEventListener('click', function () {
    if (playing) setPlaying(false);
    step();
  });
  playBtn.addEventListener('click', function () {
    setPlaying(!playing);
  });
  randomBtn.addEventListener('click', function () {
    randomize();
  });
  clearBtn.addEventListener('click', function () {
    if (playing) setPlaying(false);
    clear();
  });

  // Public API
  window.life = {
    w: W,
    h: H,
    get: get,
    set: function (x, y, v) {
      set(x, y, v);
      draw();
    },
    step: step,
    clear: clear
  };

  draw();
})();
</script>
</body>
</html>
